**Database Connection Module:**

```javascript
// src/config/db.js
const mongoose = require('mongoose');

const connectDB = async () => {
  try {
    const conn = await mongoose.connect(process.env.MONGODB_URI);
    console.log(`MongoDB Connected: ${conn.connection.host}`);

    // Event listeners
    mongoose.connection.on('error', (err) => {
      console.error(`MongoDB error: ${err}`);
    });

    mongoose.connection.on('disconnected', () => {
      console.warn('MongoDB disconnected');
    });

  } catch (error) {
    console.error(`Error: ${error.message}`);
    process.exit(1);
  }
};

module.exports = connectDB;
```

**Connection String Formats:**

```env
# Local MongoDB
MONGODB_URI=mongodb://localhost:27017/myapp

# MongoDB Atlas
MONGODB_URI=mongodb+srv://user:password@cluster.mongodb.net/myapp
```

**Using in server.js:**

```javascript
require('dotenv').config();
const connectDB = require('./src/config/db');

const startServer = async () => {
  await connectDB();
  app.listen(3000);
};

startServer();
```

**Key Points:**
- Use environment variables for connection strings
- Handle connection errors with try/catch
- Listen to connection events for monitoring
- Connect before starting the server

**findByIdAndUpdate() - Single Operation:**

```javascript
const product = await Product.findByIdAndUpdate(
  id,
  { price: 99.99 },
  { new: true, runValidators: true }
);
```

- Single database operation (faster)
- Does NOT trigger pre('save') middleware
- Does NOT trigger post('save') middleware
- Validators only run with `runValidators: true`

**find() then save() - Two Operations:**

```javascript
const product = await Product.findById(id);
product.price = 99.99;
await product.save();
```

- Two database operations (slower)
- DOES trigger pre('save') middleware
- DOES trigger post('save') middleware
- All validators run automatically
- Can use `isModified()` checks

**When to Use Each:**

| findByIdAndUpdate() | find() + save() |
|---------------------|------------------|
| Simple field updates | Password hashing needed |
| Performance critical | Need middleware to run |
| No middleware needed | Complex conditional logic |
| Atomic operations | Calculated fields |

**Example - Password (must use save):**

```javascript
// Correct - triggers password hashing middleware
const user = await User.findById(id);
user.password = newPassword;
await user.save();

// Wrong - password stored as plain text!
await User.findByIdAndUpdate(id, { password: newPassword });
```

**APIFeatures Class:**

```javascript
class APIFeatures {
  constructor(query, queryString) {
    this.query = query;
    this.queryString = queryString;
  }

  paginate() {
    const page = parseInt(this.queryString.page, 10) || 1;
    const limit = Math.min(parseInt(this.queryString.limit, 10) || 10, 100);
    const skip = (page - 1) * limit;

    this.query = this.query.skip(skip).limit(limit);
    this.pagination = { page, limit, skip };

    return this;
  }
}
```

**Controller:**

```javascript
exports.getAllProducts = async (req, res) => {
  const totalCount = await Product.countDocuments();

  const features = new APIFeatures(Product.find(), req.query).paginate();
  const products = await features.query;

  const { page, limit } = features.pagination;
  const totalPages = Math.ceil(totalCount / limit);

  res.json({
    success: true,
    count: products.length,
    pagination: {
      currentPage: page,
      totalPages,
      totalItems: totalCount,
      itemsPerPage: limit,
      hasNextPage: page < totalPages,
      hasPrevPage: page > 1
    },
    data: products
  });
};
```

