```javascript
// src/controllers/productController.js
const Product = require('../models/Product');
const asyncHandler = require('../utils/asyncHandler');
const AppError = require('../utils/AppError');

// @desc    Create a new product
// @route   POST /api/v1/products
// @access  Private/Admin
exports.createProduct = asyncHandler(async (req, res, next) => {
  const { name, description, price, category, stock } = req.body;

  // Validation
  if (!name || !description || !price || !category) {
    return next(new AppError('Please provide all required fields', 400));
  }

  if (price <= 0) {
    return next(new AppError('Price must be greater than 0', 400));
  }

  // Check for duplicate slug
  const slug = name.toLowerCase().replace(/[^a-z0-9]+/g, '-');
  const existingProduct = await Product.findOne({ slug });

  if (existingProduct) {
    return next(new AppError('A product with this name already exists', 409));
  }

  // Create product
  const product = await Product.create({
    name,
    description,
    price,
    category,
    stock: stock || 0
  });

  res.status(201).json({
    success: true,
    message: 'Product created successfully',
    data: product
  });
});
```

**With Express-Validator:**

```javascript
// src/middleware/validators/productValidator.js
const { body, validationResult } = require('express-validator');

exports.createProductRules = [
  body('name')
    .trim()
    .notEmpty().withMessage('Name is required')
    .isLength({ min: 3, max: 100 }).withMessage('Name: 3-100 chars'),

  body('description')
    .trim()
    .notEmpty().withMessage('Description is required')
    .isLength({ min: 10 }).withMessage('Description: min 10 chars'),

  body('price')
    .notEmpty().withMessage('Price is required')
    .isFloat({ min: 0.01 }).withMessage('Price must be > 0'),

  body('category')
    .notEmpty().withMessage('Category is required')
    .isIn(['electronics', 'clothing', 'books', 'home', 'other'])
    .withMessage('Invalid category')
];

exports.validate = (req, res, next) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({
      success: false,
      errors: errors.array().map(e => ({ field: e.path, message: e.msg }))
    });
  }
  next();
};
```

